INSERT INTO `attractions` VALUES (1,'Ajanta Caves',NULL,'Chhatrapati Sambhajinagar','Ancient Buddhist rock-cut cave monuments dating back to the 2nd century BCE. Famous for spectacular murals and sculptures. A UNESCO World Heritage Site.',50.00,4.5,200,NULL,'images/uploads/ajanta.png',NULL,NULL,NULL,NULL,1,0,'2026-04-05 22:21:01','2026-04-05 22:57:17'),(2,'Ellora Caves',NULL,'Chhatrapati Sambhajinagar','A UNESCO World Heritage Site featuring 34 rock-cut caves representing Hindu, Buddhist, and Jain monuments from 600├ö├ç├┤1000 CE.',50.00,4.5,200,NULL,'images/uploads/ellora_caves.png',NULL,NULL,NULL,NULL,1,0,'2026-04-05 22:21:02','2026-04-05 23:04:23'),(3,'Bibi Ka Maqbara',NULL,'Chhatrapati Sambhajinagar','Known as the Taj of the Deccan, this beautiful 17th-century Mughal mausoleum was built by Prince Azam Shah in memory of his mother.',50.00,4.5,200,NULL,'images/uploads/bibi.png',NULL,NULL,NULL,NULL,1,0,'2026-04-05 22:21:03','2026-04-05 23:04:23'),(4,'Daulatabad Fort',NULL,'Chhatrapati Sambhajinagar','One of the strongest forts in India&#039;s history, built on a conical hill with a 180-degree moat and labyrinthine passages.',50.00,4.5,200,NULL,'images/uploads/daulatabad.png',NULL,NULL,NULL,NULL,1,0,'2026-04-05 22:21:03','2026-04-05 23:04:23'),(5,'Panchakki (Water Mill)',NULL,'Chhatrapati Sambhajinagar','A scenic 17th-century water mill powered by an underground stream. Part of the Sufi shrine complex, surrounded by beautiful gardens and a serene lake.',50.00,4.5,200,NULL,'images/uploads/panchakki.jpg',NULL,NULL,NULL,NULL,1,0,'2026-04-05 22:21:03','2026-04-05 23:04:23'),(6,'Grishneshwar Temple',NULL,'Chhatrapati Sambhajinagar','One of the 12 revered Jyotirlinga shrines of Lord Shiva in India. An important pilgrimage destination with ancient architecture.',50.00,4.5,200,NULL,'images/uploads/grishneshwar-temple.jpg',NULL,NULL,NULL,NULL,1,0,'2026-04-05 22:21:03','2026-04-05 23:04:23'),(7,'Salim Ali Lake &amp;amp; Bird Sanctuary',NULL,'Chhatrapati Sambhajinagar','Peaceful lake and bird sanctuary named after famous ornithologist. Perfect for bird watching and nature walks.',50.00,4.5,200,NULL,'images/uploads/siddharth_lake.png',NULL,NULL,NULL,NULL,1,0,'2026-04-05 22:21:04','2026-04-05 23:04:23'),(8,'Siddharth Garden &amp;amp; Zoo',NULL,'Chhatrapati Sambhajinagar','Large garden with zoo, toy train, and boating facilities. Great for family outings.',50.00,4.5,200,NULL,'images/uploads/cidco_garden.png',NULL,NULL,NULL,NULL,1,0,'2026-04-05 22:21:04','2026-04-05 23:04:23'),(9,'Aurangabad Caves',NULL,'Chhatrapati Sambhajinagar','12 rock-cut Buddhist shrines dating from 3rd to 7th century. Less crowded alternative to Ajanta-Ellora.',50.00,4.5,200,NULL,'images/uploads/buddha_vihar.png',NULL,NULL,NULL,NULL,1,0,'2026-04-05 22:21:04','2026-04-05 22:57:17'),(10,'Khuldabad (Valley of Saints)',NULL,'Chhatrapati Sambhajinagar','Historic town with tombs of Mughal emperor Aurangzeb and Sufi saints. Peaceful spiritual atmosphere.',50.00,4.5,200,NULL,'images/uploads/valley_of_saints.png',NULL,NULL,NULL,NULL,1,0,'2026-04-05 22:21:01','2026-04-05 23:04:23'),(11,'Bhadra Maruti Temple',NULL,'Chhatrapati Sambhajinagar','Unique temple with reclining Hanuman idol. One of the few temples where Hanuman is in sleeping posture.',50.00,4.5,200,NULL,'images/uploads/travel-gate.jpg',NULL,NULL,NULL,NULL,1,0,'2026-04-05 22:21:01','2026-04-05 23:04:23'),(12,'Himayat Bagh',NULL,'Chhatrapati Sambhajinagar','Historic Mughal garden with beautiful landscaping. Perfect for morning walks and picnics.',50.00,4.5,200,NULL,'images/uploads/cidco_garden.png',NULL,NULL,NULL,NULL,1,0,'2026-04-05 22:21:01','2026-04-05 23:04:23'),(13,'Chhatrapati Sambhaji Maharaj Museum',NULL,'Chhatrapati Sambhajinagar','Museum showcasing history and culture of Marathwada region. Artifacts, sculptures, and paintings.',50.00,4.5,200,NULL,'images/uploads/maharashtra_museum.png',NULL,NULL,NULL,NULL,1,0,'2026-04-05 22:21:02','2026-04-05 23:04:23'),(14,'Soneri Mahal (Golden Palace)',NULL,'Chhatrapati Sambhajinagar','17th-century palace with beautiful paintings and architecture. Now houses a museum.',50.00,4.5,200,NULL,'images/uploads/travel-gate.jpg',NULL,NULL,NULL,NULL,1,0,'2026-04-05 22:21:02','2026-04-05 23:04:23'),(15,'Jama Masjid',NULL,'Chhatrapati Sambhajinagar','Historic mosque built in 1612. Beautiful Indo-Islamic architecture with intricate carvings and a large courtyard.',50.00,4.5,200,NULL,'images/uploads/travel-gate.jpg',NULL,NULL,NULL,NULL,1,0,'2026-04-05 22:21:02','2026-04-05 23:04:23');
