INSERT INTO `restaurants` VALUES (1,'Naivedya Thali Restaurant',NULL,NULL,'Chhatrapati Sambhajinagar','The most authentic Maharashtrian Thali in the city. Unlimited servings of traditional dishes ├ö├ç├┤ a cultural experience on a plate.',300.00,4.5,150,NULL,'images/uploads/indian-thali.jpg',NULL,NULL,NULL,1,0,'2026-04-05 22:21:14','2026-04-05 22:57:17'),(2,'Masala Dosa House',NULL,NULL,'Chhatrapati Sambhajinagar','Famous for crispy masala dosas, idli, vada, and filter coffee. Authentic South Indian flavors.',300.00,4.5,150,NULL,'images/uploads/masala-dosa.jpg',NULL,NULL,NULL,1,0,'2026-04-05 22:21:16','2026-04-05 22:57:17'),(3,'The Grill Room',NULL,NULL,'Chhatrapati Sambhajinagar','Indulge in rich Mughlai preparations, kebabs, biryanis, and North Indian curries in a royal ambiance.',300.00,4.5,150,NULL,'images/uploads/restaurant-north-indian.jpg',NULL,NULL,NULL,1,0,'2026-04-05 22:21:16','2026-04-05 22:57:17'),(4,'Chaat Street Corner',NULL,NULL,'Chhatrapati Sambhajinagar','Vibrant street food stall serving the best Pani Puri, Bhel, Dahi Puri, and Sev Puri in town.',300.00,4.5,150,NULL,'images/uploads/restaurant-south-indian.jpg',NULL,NULL,NULL,1,0,'2026-04-05 22:21:16','2026-04-05 22:57:17'),(5,'Renaissance Dine',NULL,NULL,'Chhatrapati Sambhajinagar','Fine dining with a wide variety of global and local cuisines. Premium experience with garden view seating.',300.00,4.5,150,NULL,'images/uploads/restaurant-thali.jpg',NULL,NULL,NULL,1,0,'2026-04-05 22:21:17','2026-04-05 22:57:17'),(6,'Biryani Blues',NULL,NULL,'Chhatrapati Sambhajinagar','Authentic Hyderabadi biryani with aromatic spices. Also serves kebabs and curries.',300.00,4.5,150,NULL,'images/uploads/north-indian-thali.jpg',NULL,NULL,NULL,1,0,'2026-04-05 22:21:17','2026-04-05 22:57:17'),(7,'Pizza Paradise',NULL,NULL,'Chhatrapati Sambhajinagar','Wood-fired pizzas with fresh toppings. Also serves pasta and Italian appetizers.',300.00,4.5,150,NULL,'images/uploads/burger.jpg',NULL,NULL,NULL,1,0,'2026-04-05 22:21:17','2026-04-05 22:57:17'),(8,'Chinese Wok',NULL,NULL,'Chhatrapati Sambhajinagar','Authentic Chinese cuisine with Indo-Chinese favorites. Noodles, fried rice, and Manchurian specialties.',300.00,4.5,150,NULL,'images/uploads/pani-puri.jpg',NULL,NULL,NULL,1,0,'2026-04-05 22:21:17','2026-04-05 22:57:17'),(9,'Burger Junction',NULL,NULL,'Chhatrapati Sambhajinagar','Gourmet burgers with variety of patties and toppings. Also serves fries and shakes.',300.00,4.5,150,NULL,'images/uploads/burger.jpg',NULL,NULL,NULL,1,0,'2026-04-05 22:21:18','2026-04-05 23:04:23'),(10,'Saffron Indian Kitchen',NULL,NULL,'Chhatrapati Sambhajinagar','Upscale restaurant with contemporary Indian cuisine. Live music on weekends.',300.00,4.5,150,NULL,'images/uploads/indian-thali.jpg',NULL,NULL,NULL,1,0,'2026-04-05 22:21:14','2026-04-05 23:04:23'),(11,'Tandoor Nights',NULL,NULL,'Chhatrapati Sambhajinagar','Specializes in tandoori dishes. Kebabs, tikkas, and naan fresh from the clay oven.',300.00,4.5,150,NULL,'images/uploads/restaurant-north-indian.jpg',NULL,NULL,NULL,1,0,'2026-04-05 22:21:14','2026-04-05 23:04:23'),(12,'Veg Delight',NULL,NULL,'Chhatrapati Sambhajinagar','100% vegetarian restaurant with Jain food options. Healthy and hygienic.',300.00,4.5,150,NULL,'images/uploads/restaurant-south-indian.jpg',NULL,NULL,NULL,1,0,'2026-04-05 22:21:15','2026-04-05 23:04:23'),(13,'Dessert Paradise',NULL,NULL,'Chhatrapati Sambhajinagar','Heaven for sweet lovers. Ice creams, cakes, pastries, and traditional Indian sweets.',300.00,4.5,150,NULL,'images/uploads/masala-dosa.jpg',NULL,NULL,NULL,1,0,'2026-04-05 22:21:15','2026-04-05 23:04:23'),(14,'Cafe Coffee Day',NULL,NULL,'Chhatrapati Sambhajinagar','Popular coffee chain with variety of hot and cold beverages. Light snacks and desserts available.',300.00,4.5,150,NULL,'images/uploads/burger.jpg',NULL,NULL,NULL,1,0,'2026-04-05 22:21:15','2026-04-05 23:04:23'),(15,'Seafood Shack',NULL,NULL,'Chhatrapati Sambhajinagar','Fresh seafood preparations with coastal flavors. Fish, prawns, and crab specialties.',300.00,4.5,150,NULL,'images/uploads/restaurant-thali.jpg',NULL,NULL,NULL,1,0,'2026-04-05 22:21:15','2026-04-05 23:04:23');
/*!40000 ALTER TABLE `restaurants` ENABLE KEYS */;
UNLOCK TABLES;

