INSERT INTO `stays` VALUES (1,NULL,'ITS HOME ΓÇô Home Stay Inn','Homestay','Chhatrapati Sambhajinagar','A cozy and comfortable homestay in the heart of Chhatrapati Sambhajinagar. Perfect for families and solo travelers looking for a home-like experience.',999.00,4.3,0,NULL,'images/uploads/its-home-home-stay-inn-stays-main.jpeg','[\"images\\/uploads\\/its-home-home-stay-inn-stays-gallery (1).jpeg\",\"images\\/uploads\\/its-home-home-stay-inn-stays-gallery (2).jpeg\",\"images\\/uploads\\/its-home-home-stay-inn-stays-gallery (3).jpeg\",\"images\\/uploads\\/its-home-home-stay-inn-stays-gallery (4).jpeg\"]','[\"Wi-Fi\",\"Parking\",\"Hot Water\",\"TV\"]',NULL,2,NULL,1,2,'2026-04-06 16:41:11','2026-04-07 00:41:16'),(2,NULL,'Its Home ΓÇô Service Apartments','Service Apartment','Chhatrapati Sambhajinagar','Fully furnished service apartments with kitchen facilities. Ideal for long stays and business travelers in Chhatrapati Sambhajinagar.',1499.00,4.4,0,'','images/uploads/its-home-service-apartments-stays-main.webp','[\"images\\/uploads\\/its-home-service-apartments-stays-gallery (1).webp\",\"images\\/uploads\\/its-home-service-apartments-stays-gallery (2).webp\",\"images\\/uploads\\/its-home-service-apartments-stays-gallery (3).webp\",\"images\\/uploads\\/its-home-service-apartments-stays-gallery (4).webp\",\"images\\/uploads\\/its-home-service-apartments-stays-gallery (5).webp\",\"images\\/uploads\\/its-home-service-apartments-stays-gallery (6).webp\"]','[\"Wi-Fi\",\"Kitchen\",\"Parking\",\"AC\",\"Washing Machine\"]','',2,NULL,1,0,'2026-04-06 16:41:11','2026-04-07 00:41:16'),(3,NULL,'Treebo Aroma Executive','Business Hotel','Chhatrapati Sambhajinagar','A premium business hotel offering executive rooms with modern amenities. Treebo certified quality with complimentary breakfast.',1800.00,4.2,0,'','images/uploads/treebo-aroma-executive-stays-main.webp','[\"images\\/uploads\\/treebo-aroma-executive-stays-gallery (1).webp\",\"images\\/uploads\\/treebo-aroma-executive-stays-gallery (2).webp\",\"images\\/uploads\\/treebo-aroma-executive-stays-gallery (3).webp\",\"images\\/uploads\\/treebo-aroma-executive-stays-gallery (4).webp\",\"images\\/uploads\\/treebo-aroma-executive-stays-gallery (5).webp\",\"images\\/uploads\\/treebo-aroma-executive-stays-gallery (6).webp\"]','[\"Wi-Fi\",\"Breakfast\",\"AC\",\"Room Service\",\"Parking\"]','',2,NULL,1,1,'2026-04-06 16:41:11','2026-04-07 00:41:16'),(4,NULL,'Hotel Blossom','Budget Hotel','Chhatrapati Sambhajinagar','Clean and affordable hotel in Chhatrapati Sambhajinagar. Great value for money with all essential amenities for a comfortable stay.',1200.00,4.1,0,'Budget','images/uploads/hotel-blossom-stays-main.jpeg','[]','[\"Wi-Fi\",\"AC\",\"TV\",\"Hot Water\"]',NULL,2,NULL,1,3,'2026-04-06 16:41:11','2026-04-07 00:41:16'),(5,NULL,'Hotel The Gravity Inn','Premium Hotel','Silicon City, Indore','A top-rated premium hotel in Silicon City, Indore. Featuring free Wi-Fi, complimentary breakfast, and world-class amenities for a luxurious stay.',2172.00,4.7,0,'Top Rated','images/uploads/hotel-the-gravity-inn-stays-main.webp','[\"images\\/uploads\\/hotel-the-gravity-inn-stays-gallery (1).webp\",\"images\\/uploads\\/hotel-the-gravity-inn-stays-gallery (2).webp\",\"images\\/uploads\\/hotel-the-gravity-inn-stays-gallery (3).webp\",\"images\\/uploads\\/hotel-the-gravity-inn-stays-gallery (4).webp\"]','[\"Free Wi-Fi\",\"Free Breakfast\",\"AC\",\"Parking\",\"Room Service\",\"Swimming Pool\"]',NULL,2,NULL,1,4,'2026-04-06 16:41:11','2026-04-07 00:41:16'),(6,NULL,'Hotel O Indraprasth','Budget Hotel','Silicon City, Indore','Budget-friendly hotel in Silicon City, Indore with free parking and Wi-Fi. Perfect for travelers looking for affordable accommodation.',840.00,3.1,0,'Budget','images/uploads/hotel-o-indraprasth-stays-main.jpeg','[\"images\\/uploads\\/hotel-o-indraprasth-stays-gallery (1).jpeg\",\"images\\/uploads\\/hotel-o-indraprasth-stays-gallery (2).jpeg\",\"images\\/uploads\\/hotel-o-indraprasth-stays-gallery (3).jpeg\",\"images\\/uploads\\/hotel-o-indraprasth-stays-gallery (4).jpeg\"]','[\"Free Parking\",\"Free Wi-Fi\",\"AC\",\"TV\"]',NULL,2,NULL,1,5,'2026-04-06 16:41:11','2026-04-07 00:41:16');
